233→    /**
234→     * On rotating the device onSizeChanged() helps to stretch the previously created Bitmap rather
235→     * than creating a new Bitmap which makes sure bitmap doesn't go out of screen.
236→     */
237→    override fun onSizeChanged(w: Int, h: Int, oldw: Int, oldh: Int) {
238→        super.onSizeChanged(w, h, oldw, oldh)
239→        // createScaledBitmap requires a width and height > 0; #13972
240→        if (w <= 0 || h <= 0) {
241→            Timber.w("Width or height <= 0: w: $w h: $h Bitmap couldn't be created with the new size")
242→            return
