249→    private fun drawStart(x: Float, y: Float) {
250→        isCurrentlyDrawing = true
251→        mPath.reset()
252→        mPath.moveTo(x, y)
253→        mX = x
254→        mY = y
255→    }
256→
257→    private fun drawAlong(x: Float, y: Float) {
258→        val dx = abs(x - mX)
259→        val dy = abs(y - mY)
260→        if (dx >= TOUCH_TOLERANCE || dy >= TOUCH_TOLERANCE) {
261→            mPath.quadTo(mX, mY, (x + mX) / 2, (y + mY) / 2)
262→            mX = x
263→            mY = y
264→        }
265→    }
266→
267→    private fun drawFinish() {
268→        isCurrentlyDrawing = false
269→        val pm = PathMeasure(mPath, false)
270→        mPath.lineTo(mX, mY)
271→        val paint = Paint(mPaint)
272→        val action = if (pm.length > 0) DrawPath(Path(mPath), paint) else DrawPoint(mX, mY, paint)
273→        action.apply(mCanvas)
274→        mUndo.add(action)
275→        // kill the path so we don't double draw
276→        mPath.reset()
277→        if (mUndo.size() == 1) {
278→            mAnkiActivity.invalidateOptionsMenu()
279→        }
280→    }
281→
282→    private fun drawAbort() {
283→        drawFinish()
284→        undo()
285→    }
