287→    // call this with an ACTION_POINTER_DOWN event to start a new round of detecting drag or tap with
288→    // a second finger
289→    private fun reinitializeSecondFinger(event: MotionEvent) {
290→        mSecondFingerWithinTapTolerance = true
291→        mSecondFingerPointerId = event.getPointerId(event.actionIndex)
292→        mSecondFingerX0 = event.getX(event.findPointerIndex(mSecondFingerPointerId))
293→        mSecondFingerY0 = event.getY(event.findPointerIndex(mSecondFingerPointerId))
294→    }
295→
296→    private fun updateSecondFinger(event: MotionEvent): Boolean {
297→        val pointerIndex = event.findPointerIndex(mSecondFingerPointerId)
298→        if (pointerIndex > -1) {
299→            mSecondFingerX = event.getX(pointerIndex)
300→            mSecondFingerY = event.getY(pointerIndex)
301→            val dx = abs(mSecondFingerX0 - mSecondFingerX)
302→            val dy = abs(mSecondFingerY0 - mSecondFingerY)
303→            if (dx >= TOUCH_TOLERANCE || dy >= TOUCH_TOLERANCE) {
304→                mSecondFingerWithinTapTolerance = false
305→            }
306→            return true
307→        }
308→        return false
309→    }
310→
311→    // call this with an ACTION_POINTER_UP event to check whether it matches a tap of the second finger
312→    // if so, forward a click action and return true
313→    private fun trySecondFingerClick(event: MotionEvent): Boolean {
314→        if (mSecondFingerPointerId == event.getPointerId(event.actionIndex)) {
315→            updateSecondFinger(event)
316→            if (mSecondFingerWithinTapTolerance && mWhiteboardMultiTouchMethods != null) {
317→                mWhiteboardMultiTouchMethods!!.tapOnCurrentCard(mSecondFingerX.toInt(), mSecondFingerY.toInt())
318→                return true
319→            }
320→        }
321→        return false
322→    }
323→
324→    // call this with an ACTION_MOVE event to check whether it is within the threshold for a tap of the second finger
325→    // in this case perform a scroll action
326→    private fun trySecondFingerScroll(event: MotionEvent): Boolean {
327→        if (updateSecondFinger(event) && !mSecondFingerWithinTapTolerance) {
328→            val dy = (mSecondFingerY0 - mSecondFingerY).toInt()
329→            if (dy != 0 && mWhiteboardMultiTouchMethods != null) {
330→                mWhiteboardMultiTouchMethods!!.scrollCurrentCardBy(dy)
331→                mSecondFingerX0 = mSecondFingerX
332→                mSecondFingerY0 = mSecondFingerY
333→            }
334→            return true
335→        }
336→        return false
337→    }
