415→    /**
416→     * Keep a list of all points and paths so that the last stroke can be undone
417→     * pop() removes the last stroke from the list, and apply() redraws it to whiteboard.
418→     */
419→    private inner class UndoList {
420→        private val mList: MutableList<WhiteboardAction> = ArrayList()
421→        fun add(action: WhiteboardAction) {
422→            mList.add(action)
423→        }
424→
425→        fun clear() {
426→            mList.clear()
427→        }
428→
429→        fun size(): Int {
430→            return mList.size
431→        }
432→
433→        fun pop() {
434→            mList.removeAt(mList.size - 1)
435→        }
436→
437→        fun apply() {
438→            mBitmap.eraseColor(0)
439→            for (action in mList) {
440→                action.apply(mCanvas)
441→            }
442→            invalidate()
443→        }
444→
445→        fun erase(x: Int, y: Int): Boolean {
446→            var didErase = false
447→            val clip = Region(0, 0, displayDimensions.x, displayDimensions.y)
448→            val eraserPath = Path()
449→            eraserPath.addRect((x - 10).toFloat(), (y - 10).toFloat(), (x + 10).toFloat(), (y + 10).toFloat(), Path.Direction.CW)
450→            val eraserRegion = Region()
451→            eraserRegion.setPath(eraserPath, clip)
452→
453→            // used inside the loop – created here to make things a little more efficient
454→            val bounds = RectF()
455→            var lineRegion = Region()
456→
457→            // we delete elements while iterating, so we need to use an iterator in order to avoid java.util.ConcurrentModificationException
458→            val iterator = mList.iterator()
459→            while (iterator.hasNext()) {
460→                val action = iterator.next()
461→                val path = action.path
462→                if (path != null) { // → line
463→                    val lineRegionSuccess = lineRegion.setPath(path, clip)
464→                    if (!lineRegionSuccess) {
465→                        // Small lines can be perfectly vertical/horizontal,
466→                        // thus giving us an empty region, which would make them undeletable.
467→                        // For this edge case, we create a Region ourselves.
468→                        path.computeBounds(bounds, true)
469→                        lineRegion = Region(Rect(bounds.left.toInt(), bounds.top.toInt(), bounds.right.toInt() + 1, bounds.bottom.toInt() + 1))
470→                    }
471→                } else { // → point
472→                    val p = action.point
473→                    lineRegion = Region(p!!.x, p.y, p.x + 1, p.y + 1)
474→                }
475→                if (!lineRegion.quickReject(eraserRegion) && lineRegion.op(eraserRegion, Region.Op.INTERSECT)) {
476→                    iterator.remove()
477→                    didErase = true
478→                }
479→            }
480→            return didErase
481→        }
482→
483→        fun empty(): Boolean {
484→            return mList.isEmpty()
485→        }
486→    }
